mapper.select:
SELECT r.review_id AS reviewId, r.user_id AS userId, r.place_id AS placeId, r.rating, r.content, r.created_at AS createdAt, u.nickname AS userNickname, p.name AS placeName FROM reviews r JOIN users u ON r.user_id = u.user_id JOIN places p ON r.place_id = p.place_id
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR r.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
AND r.rating = #{rating}
AND r.created_at >= #{startDate}
AND r.created_at <= CONCAT(#{endDate}, ' 23:59:59')
ORDER BY r.created_at DESC
